def move_cell_cols_from_buffer(
    conn: sqlite3.Connection,
    src_start: int,
    src_end: int,
    final_start: int,
    width: int,
    sheet_id: str,
) -> None:
    sql = """\
update datasette_sheets_cell
set col_idx = case
  when (-col_idx - 1) between $src_start::integer and $src_end::integer
    then (-col_idx - 1) - $src_start::integer + $final_start::integer
  when (-col_idx - 1) < $src_start::integer
    then (-col_idx - 1) + $width::integer
  else (-col_idx - 1) - $width::integer
end
where sheet_id = $sheet_id::text
  and col_idx < 0;
"""
    params = {
        "src_start::integer": src_start,
        "src_end::integer": src_end,
        "final_start::integer": final_start,
        "width::integer": width,
        "sheet_id::text": sheet_id,
    }
    conn.execute(sql, params)
