def update_dropdown_rule(
    conn: sqlite3.Connection,
    name_do_update: bool,
    name: str | None,
    multi_do_update: bool,
    multi: int,
    options_do_update: bool,
    options_json: str,
    rule_id: str,
    workbook_id: str,
) -> DropdownRule | None:
    sql = """\
update datasette_sheets_dropdown_rule
set name = case
        when $name_do_update::boolean then $name::text::
        else name
    end,
    multi = case
        when $multi_do_update::boolean then $multi::integer
        else multi
    end,
    options_json = case
        when $options_do_update::boolean then $options_json::text
        else options_json
    end,
    updated_at = strftime('%Y-%m-%dT%H:%M:%f', 'now')
where id = $rule_id::text
  and workbook_id = $workbook_id::text
returning id, workbook_id, name, multi, options_json, updated_at;
"""
    params = {
        "name_do_update::boolean": name_do_update,
        "name::text::": name,
        "multi_do_update::boolean": multi_do_update,
        "multi::integer": multi,
        "options_do_update::boolean": options_do_update,
        "options_json::text": options_json,
        "rule_id::text": rule_id,
        "workbook_id::text": workbook_id,
    }
    cursor = conn.execute(sql, params)
    row = cursor.fetchone()
    return DropdownRule(*row) if row is not None else None


